var mArr = ['Jan', 'Feb','Mar','Apr','May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']
function ordinal($number) {
    $ends = ['th', 'st', 'nd', 'rd', 'th', 'th', 'th', 'th', 'th', 'th'];
    if ((($number % 100) >= 11) && (($number % 100) <= 13))
        return $number + 'th';
    else
        return $number + $ends[$number % 10];
}
function addZero(digit){
    var num = digit;
    if(digit < 10)
        num = '0'+digit;
    return num;    
}
function dateFormat(date) {
    var d = new Date(date)
    d = addZero(d.getDate())+"-"+mArr[d.getMonth()]+"-"+d.getFullYear()+"";
    return d.indexOf('NaN') == -1 ? d : '';
}
function kvDatePicker(date = '.date'){
    var curYear = new Date().getFullYear()+2;
    var objD = {dateFormat: 'dd-M-yy', changeMonth: true,changeYear: true,yearRange: '1900:'+curYear,};
    if (date == '.date-l') {
        objD['minDate'] = new Date();
    }
    $(date).datepicker(objD);  
    $(date).parent().addClass('date-wrapper')             
}

$(document).ready(function () {
    kvDatePicker()
    kvDatePicker('.date-l')
    $('.datetime').datetimepicker({
        format: 'dd-mm-yyyy hh:ii',
        autoclose: true,
        buttonImage: "http://jqueryui.com/resources/demos/datepicker/images/calendar.gif",
        // date:  new Date(1434544882775),
    });
});

