function p_r_fields(){
    $('.row-wraper.p-create-wrap.todo-2 .pas-wrap.p-create').each(function(index){
        if(index > 0)
        {
            $(this).find('.pas-name input, .p-email input').removeAttr('required')
            $(this).find('.p-email label span.required').remove()
        }
        else
        {
            if($('[name="client_type"]').val() == '1'){
                $(this).find('.pas-name input, .p-email input').attr('required', 'required')
                $(this).find('.pas-name label span.required, .p-email label span.required').remove()   
                $(this).find('.pas-name label, .p-email label').append(' <span class="required">*</span>')   
            }
        }
    })
}
var lPass = $('.p-create-wrap .pas-wrap:eq(0)').html();
$(document).on('click', '.add-row-wrap a.remove-row', function (e) {
    var curElem = this;
    var curPRow = $(this).closest('.p-r-wrap');
    var curRow = $(this).closest('.pas-wrap');
    let rowObj = $(this).closest('.p-r-wrap').find('.pas-wrap');
    let curRow2 = $(this).closest('.row-wraper').find('.pas-wrap');
    let curPRow2 = $(this).closest('.row-wraper');
    if (($(this).closest('.row-wraper').find('.pas-wrap').length - 1) == 1)
        $(this).closest('.row-wraper').find('.pas-wrap .remove-row').remove();
    var lastAdd = false;
    if (curPRow.length) {
        curRow.remove();
        rowObj.each(function (i) {
            let pName = $('select[name="contact_type"]').val() || 'Lead Passenger';
            if (i > 0)
                pName = ordinal(i + 1) + " Passenger"
            $('.p-r-wrap').find('.pas-wrap').eq(i).find('.pas-name label').text(pName)
        })
        if($('.p-create-wrap .pas-wrap:eq(0) input[name="passengers[email][]"]').length){
            // $('.p-create-wrap .pas-wrap:eq(0)').html(lPass)
            if($('.p-create-wrap .pas-wrap').length > 1){
                $('.p-create-wrap .pas-wrap:eq(0) .add-row-wrap .kv-row').removeClass('add-row').addClass('remove-row')
            }
        }
    }
    curRow2.each(function (i) {
        if ($(this).find('.add-row').length == 0)
            lastAdd = true
    });
    curRow.remove();
    if (lastAdd) {
        if (curPRow2.find('.pas-wrap').eq(curRow.find('.pas-wrap').length - 1).find('.add-row').length == 0)
            curPRow2.find('.pas-wrap').eq(curRow.find('.pas-wrap').length - 1).find('.add-row-wrap').prepend('<a href="javascript:;" class="kv-row add-row"></a>')
    }
    p_r_fields();
});
