$('.view-users').click(function () {
    $('#viewUserModal table tbody').html('<tr><td colspan="4" align="center">Loading...</td></tr>');
    $.ajax({
        url: localStorage.getItem('site_url') + 'api/v1/notification-by-group',
        type: 'post',
        data: {group_id: $(this).attr('group-id')},
        success: function (data) {
            data = JSON.parse(data).data;
            var tHtml = '';
            $.each(data, function (key, val) {
                tHtml += '<tr>';
                tHtml += '<td>' + val.id + '</td>';
                tHtml += '<td>' + val.name + '</td>';
                tHtml += '<td>' + val.reference_number + '</td>';
                tHtml += '<td>' + val.email + '</td>';
                tHtml += '</tr>'
            })
            $('#viewUserModal table tbody').html(tHtml);
        },
        error: function () {
            $('#viewUserModal table tbody').html('<tr><td colspan="4" align="center">Something went wrong!</td></tr>');
        }
    });
});
$('.resend-btn').click(function () {
    var tr = $(this).closest('tr');
    $.ajax({
        url: localStorage.getItem('site_url') + 'resend-notification',
        type: 'post',
        data: {group_id: $(this).attr('group-id'), title: tr.find('td:eq(1)').text(), msg: tr.find('td:eq(2)').text(), group_name: tr.find('td:eq(3)').text()},
        success: function (data) {
            if (data == 1) {
                location.href = localStorage.getItem('site_url') + 'notification';
            }
        },
        error: function () {
            alert('Something went wrong!');
        }
    });
});
