function lnSelectt2(params, data) {
    if ($.trim(params.term) === '') {
      return data;
  }
  if (typeof data.text === 'undefined' || !$(data.element).data('reference_number')) {
    return null;
}
    // if ($(data.element).data('reference_number')) {  
        // if ($(data.element).data('reference_number').toString().toLowerCase().indexOf(params.term.toLowerCase()) > -1) {
        //     var modifiedData = $.extend({}, data, true);
        //     return modifiedData;
        // }
    // }  
    if ($(data.element).data('reference_number').toString().toLowerCase().indexOf(params.term.toLowerCase()) > -1) {
        var modifiedData = $.extend({}, data, true);
        return modifiedData;
    }
    else if(data.text.toString().toLowerCase().indexOf(params.term.toLowerCase()) > -1){
        var modifiedData = $.extend({}, data, true);
        return modifiedData;
    }
    return null;
}
