$('select[name="action"]').change(function () {
    var url = document.URL.split('report/')[1]
    if (!url) 
        url = document.URL.split('user/')[1]
    url = url ? '&l='+url : '';
    if($(this).val() == 'delete')
        $('#report-form').attr('action', localStorage.getItem('site_url')+'user/delete?r=true'+url);
    else if($(this).val() == 'rm_email')
        $('#report-form').attr('action', localStorage.getItem('site_url')+'user/resend-email');
    else if($(this).val() == 'app_email')
        $('#report-form').attr('action', localStorage.getItem('site_url')+'user/rm-email?p=login'+url);

    if ($(this).val() != '' && !$(this).hasClass('rf'))
        $('.action-form').submit();
    if ($(this).val() != '' && $(this).hasClass('rf'))
        $('#report-form').submit();
});
$('.action-form, #report-form').submit(function () {
    var ids = [];
    $('input[name="ids[]"]').each(function () {
        if ($(this).is(':checked'))
            ids.push($(this).val())
    })
    if (ids.length == 0) {
        alert('Please select at least one checkbox');
        $('select[name="action"] option:eq(0)').prop('selected', 'selected');
        return false;
    }
    if($('select[name="action"]').val() == 'delete'){
        if (!confirm('Are you sure?')) {
            $('select[name="action"] option:eq(0)').prop('selected', 'selected');
            return false;
        }
    }
});
function getLatLng(isSubmit = null) {
    // setTimeout(() => {
        var geocoder = new google.maps.Geocoder();
        var address = $('#pac-input').val();
        geocoder.geocode({'address': address}, (results, status) => {
            if (results) {
                if (results[0]) {
                    if (results[0].geometry) {
                        if (results[0].geometry.location) {
                            $('input[name="lat"]').val(results[0].geometry.location.lat());
                            $('input[name="lng"]').val(results[0].geometry.location.lng());
                            if (isSubmit) {
                                $('#pac-input').closest('form').unbind('submit');
                                $('#pac-input').closest('form').submit();
                            }
                        }
                    }
                }
            }
        });
    // }, 100)
}
window.onload = function () {
    if (document.getElementById('pac-input')) {
        var map = new google.maps.Map(document.getElementById('map'), {
            center: {lat: -33.8688, lng: 151.2195},
            zoom: 13
        });
        var card = document.getElementById('pac-card');
        var input = document.getElementById('pac-input');
        var types = document.getElementById('type-selector');
        var strictBounds = document.getElementById('strict-bounds-selector');


        map.controls[google.maps.ControlPosition.TOP_RIGHT].push(card);
        var options = {
            componentRestrictions: {country: "pk"}
        };
        var autocomplete = new google.maps.places.Autocomplete(input, {});
        autocomplete.bindTo('bounds', map);
        autocomplete.setFields(
            ['address_components', 'geometry', 'icon', 'name']);

        var infowindow = new google.maps.InfoWindow();
        var infowindowContent = document.getElementById('infowindow-content');
        infowindow.setContent(infowindowContent);
        var marker = new google.maps.Marker({
            map: map,
            anchorPoint: new google.maps.Point(0, -29)
        });

        autocomplete.addListener('place_changed', function () {
            infowindow.close();
            marker.setVisible(false);
            var place = autocomplete.getPlace();
            if (!place.geometry) {
                // window.alert("No details available for input: '" + place.name + "'");
                return;
            }
            if (place.geometry.viewport) {
                map.fitBounds(place.geometry.viewport);
            } else {
                map.setCenter(place.geometry.location);
                map.setZoom(17);  // Why 17? Because it looks good.
            }
            marker.setPosition(place.geometry.location);
            marker.setVisible(true);
            var address = '';
            if (place.address_components) {
                address = [
                (place.address_components[0] && place.address_components[0].short_name || ''),
                (place.address_components[1] && place.address_components[1].short_name || ''),
                (place.address_components[2] && place.address_components[2].short_name || '')
                ].join(' ');
            }
        });
    }
}
