$(document).on('change', '.from.range.date', function(){
    var date = $(this).val().replace(/-/g, '/');
    var to = $(this).parent().siblings('.col-md-4.col-sm-9.col-xs-12 ').find('.to.range.date');
    date = new Date(date.substr(7,4)+'/'+date.substr(3,3)+'/'+date.substr(0,2));
    if (date != 'Invalid Date') {
        to.removeAttr('disabled');
        to.attr('required', 'required');
    }
    else
        to.attr('disabled', 'disabled');
    to.datepicker('option', 'minDate', date);
});
function makeMenu(elem){
    $(elem).each(function(){
        if ($(this).find('a').attr('href') == document.URL.split('?')[0]) {
            if($(this).closest('.child_menu').length != 0){
                $(this).closest('.child_menu').slideToggle();
                $(this).closest('.child_menu').parent('li').parent('.nav.child_menu').slideToggle();
                $(this).addClass('active');
            }
            else
                $(this).addClass('active');
        }
        // console.log($(this).find('a:eq(0)').attr('href'))
        // if ($(this).) {}
    })
}
