function dropDown(args){
    var res = args.data;
    var dropD = args.dropDown;
    var wrap = args.wrap;
    var mDiv = args.mDiv;
    var dropD = args.dropD;
    var html = args.html;
    if(res.data[dropD].length > 0){
        var desHTML = '';
        if(html){
            desHTML = '<div class="p-r-wrap  passengers ">' ;
            desHTML += html.repeat(res.data[dropD].length);
            desHTML += '</div>' ;
        }
        else{
            var desHTML = $(mDiv)[0].outerHTML.repeat(res.data[dropD].length);
        }
        $(wrap).html(desHTML)
    }
    else{
        $(wrap).html(fTrip)
    }
    $(wrap).html(desHTML)
    $(mDiv+' span.select2-selection.select2-selection--single').remove();
    $(mDiv+' select').removeClass(' select2-hidden-accessible').select2();
    var countries = []
    $(mDiv+' span.select2.select2-container.select2-container--default').remove();
    $(mDiv+' select').removeClass('select2-hidden-accessible').select2();
    if(res.data[dropD].length > 0){
        $.each(res.data[dropD], function(mkey,val){
            var country = {};
            if ($(mDiv).eq(mkey).find('select option:contains("'+val.country+'")').length ) {
                $(mDiv).eq(mkey).find('select option:contains("'+val.country+'")').attr('selected', 'selected').trigger('change')
            }
            else{
                country['name'] = val.country; 
                var geocoder = new google.maps.Geocoder();
                geocoder.geocode({'address': val.country}, (results, status) => {
                    if (results) {
                        if (results[0]) {
                            if (results[0].geometry) {
                                if (results[0].geometry.location) {
                                    country['lat'] = results[0].geometry.location.lat()
                                    country['lng'] = results[0].geometry.location.lng()
                                    country['ajax'] = 1;
                                    $.ajax({
                                        type: 'post',
                                        url: localStorage.getItem('site_url')+'destination/create',
                                        data: country,
                                        async: false,
                                        success: function (res2) {
                                            if(res2.includes('<!DOCTYPE html>'))
                                                return;
                                            var opt2 = "";
                                            $.each(JSON.parse(res2), function(key,val){
                                                opt2 += '<option value="'+val.id+'">'+val.name+'</option>'
                                            });
                                            $(mDiv+' select').html(opt2);

                                            $(mDiv+' span.select2.select2-container.select2-container--default').remove();
                                            $(mDiv+' select').removeClass('select2-hidden-accessible').select2();
                                            var t = false;
                                            setTimeout(function(){
                                                $(wrap).find('select:eq('+mkey+') option:contains("'+res.data[dropD][mkey].country+'"):eq(0)').attr('selected', 'selected').trigger('change')
                                            },1000)
                                                // $('.page-loader').fadeOut();
                                            }
                                        });
                                }
                            }
                        }
                    }
                });
                countries.push(country); 
            }
        })
    }
    else{
        $(mDiv+':not(":first")').remove();
        $(mDiv+' option').removeAttr('selected').change();
    }
    $(mDiv+' .kv-row').removeClass('add-row').addClass('remove-row');
    if ($(mDiv).length > 1) {
        $(mDiv+':last-child .add-row-wrap').html('<a href="javascript:;" class="kv-row add-row"></a><a href="javascript:;" class="kv-row remove-row"></a>')
    }
    else{
        $(mDiv+':last-child .add-row-wrap').html('<a href="javascript:;" class="kv-row add-row"></a>')
    }
    if(html){
        $(mDiv).each(function(index){
            if(index == 0){
                var p_name = $('select[name="contact_type"]').val() || 'Lead Passenger';
                $(this).find('.form-group.pas-name label').html(p_name+' <span class="required">*</span>');
                if(res.data.client_type == '1'){
                    $(this).find('.p-email label .required').remove();
                    $(this).find('.p-email input').attr('required', 'required');
                    $(this).find('.p-email label').append('<span class="required">*</span>');
                }
                else if(res.data.client_type == '2'){
                    $(this).find('.pas-name label .required,.p-email label .required').remove();
                    $(this).find('.pas-name input,.p-email input').removeAttr('required');
                }
            }
            else{
                $(this).find('.form-group.pas-name label').text(ordinal(index+1)+" Passenger");
                $(this).find('.form-group.pas-name input, .form-group.p-email input').removeAttr('required');
                $(this).find('.form-group.p-email label span.required').remove();
            }
            var pData = res.data[dropD][index];
            var fullName = '';
            if(pData.first_name){
                fullName += pData.first_name;
            }
            if(pData.middle_name){
                fullName += ' '+pData.middle_name;
            }
            if(pData.last_name){
                fullName += ' '+pData.last_name;
            }

            $(this).find('.form-group [name="passengers[name][]"]').val(fullName)
            if(pData.dob)
                $(this).find('.form-group [name="passengers[date_of_birth][]"]').val(dateFormat(pData.dob.replace(/ /g, '')))
            if(index == 0){
                if($('input[name="client_type"]').val() == 1)
                    $(this).find('.form-group [name="passengers[email][]"]').val(args.email);
            }else{
                $(this).find('.form-group [name="passengers[email][]"]').val(pData.email)                
            }
            $(this).find('.form-group [name="passengers[bedding_preferences][]"]').val(pData.bedding_preference)
            $(this).find('.form-group [name="passengers[dietary_preference][]"]').val(pData.dietary_preference)
        })
        kvDatePicker();
        $('body [name="username"]').change()
    }
        // if(res.data.client_type == '1'){
        //     $('.p-r-wrap.passengers .pas-wrap.p-create:eq(0) .pas-name label .required, .p-r-wrap.passengers .pas-wrap.p-create:eq(0) .p-email label .required').remove();
        //     $('.p-r-wrap.passengers .pas-wrap.p-create:eq(0) .pas-name input, .p-r-wrap.passengers .pas-wrap.p-create:eq(0) .pas-name input').attr('required', 'required');
        //     $('.p-r-wrap.passengers .pas-wrap.p-create:eq(0) .pas-name label, .p-r-wrap.passengers .pas-wrap.p-create:eq(0) .p-email label').append('<span class="required">*</span>');
        // }
        // else if(res.data.client_type == '2'){
        //     $('.p-r-wrap.passengers .pas-wrap.p-create:eq(0) .pas-name label .required, .p-r-wrap.passengers .pas-wrap.p-create:eq(0) .p-email label .required').remove();
        //     $('.p-r-wrap.passengers .pas-wrap.p-create:eq(0) .pas-name input, .p-r-wrap.passengers .pas-wrap.p-create:eq(0) .pas-name input').removeAttr('required');
        // }
        // $('[name="email"], [name="passengers[email][]"]:eq(0)').keyup();
    }
    var linkCopyTxt = $('.copy-link').attr('tooltip');
    $(document).on('click', '.copy-link', function(e){
        e.preventDefault();
        $(this).after('<input type="text" class="copy-l-t" />');
        $('.copy-l-t').val($(this).attr('href'));
        $('.copy-l-t').select();
        document.execCommand("copy");
        $('.copy-l-t').remove();
        $(this).attr('tooltip', 'Copied!');
    })
    $(document).on('mouseenter', '.copy-link', function(e){
        $(this).attr('tooltip', linkCopyTxt);
    })

    $('[name="date_of_travel"]').change(function(){
        var td = $(this).val().substr(7,4)+"/"+$(this).val().substr(3,3)+"/"+$(this).val().substr(0,2);
        var d = new Date(td);
        d.setMonth(d.getMonth() - 2);
        var day = d.getDate()+"";
        if(day.indexOf('NaN') == -1)
            $('[name="deadline"]').val(addZero(d.getDate())+"-"+mArr[d.getMonth()]+"-"+d.getFullYear());
        else
            $('[name="deadline"]').val('');
    });
