$('.unfor-form.c-u-f').submit(function (e) {
    if($(this).attr('kv_submit') == 'true')
        e.preventDefault()
    else{
        return;
    }
    $.ajax({
        url: "",
        type: "post",
        assync: false,
        data: $('.unfor-form.c-u-f').serialize(), 
        success: (data) =>{
            if(data)
            {   
                var errorMsg = JSON.parse(data).errormsg;
                if(errorMsg){
                    $('.main-view .ajax-u-em.alert.alert-danger, .alert.alert-success.col-sm-8.col-sm-offset-2').remove()
                    $('.main-view').prepend('<div class="ajax-u-em alert alert-danger col-sm-8 col-sm-offset-2"><h2>'+errorMsg+'</h2></div>');
                    scrollTo(0,0);
                    $(this).attr('kv_submit', 'true');
                    return false;
                }
                else{
                    $('.ajax-u-em.alert.alert-danger.col-sm-8.col-sm-offset-2, .alert.alert-success.col-sm-8.col-sm-offset-2').remove();
                    $(this).attr('kv_submit', 'false');
                    $(this).submit();
                }
            }
            else{
                $('.ajax-u-em.alert.alert-danger.col-sm-8.col-sm-offset-2, .alert.alert-success.col-sm-8.col-sm-offset-2').remove();
                $(this).attr('kv_submit', 'false')
                $(this).submit();
            }
        },
        error: function(){
            alert('Something went wrong!');
        }
    })
});
