$('.app-u-form').submit(function (e) {
    if ($(this).hasClass('update'))
        return;
    if($('.app-u-form').attr('kv_submit') == 'true')
        e.preventDefault()
    else
        return;
    var obj = [];
    $('form.app-u-form .pas-wrap.p-create').each(function(){
        let key = $(this).find('[name="labels[]"]').val();
        var file = $(this).find('[name="files[]"]').val() ? $(this).find('[name="files[]"]').val() : $(this).find('.file-u-txt').text();
        obj.push({[key]: file});
    })
    $("#ajaxLoader").show();
    $('[name="fData"]').val(JSON.stringify(obj));
    $.ajax({
        url: $(this).attr('action'),
        type: "post",
        assync: false,
        data: $(this).serialize(), 
        success: (data) =>{
            if(data)
            {   
                var errorMsg = JSON.parse(data).errormsg;
                if(errorMsg){
                    $('.main-view .ajax-u-em.alert.alert-danger, .alert.alert-success.col-sm-8.col-sm-offset-2').remove()
                    $('.main-view').prepend('<div class="ajax-u-em alert alert-danger col-sm-8 col-sm-offset-2"><h2>'+errorMsg+'</h2></div>');
                    scrollTo(0,0);
                    $('.app-u-form').attr('kv_submit', 'true');
                    return false;
                }
                else{
                    $('.ajax-u-em.alert.alert-danger.col-sm-8.col-sm-offset-2, .alert.alert-success.col-sm-8.col-sm-offset-2').remove();
                    $('.app-u-form').attr('kv_submit', 'false');
                    $('.app-u-form').submit();
                }
            }
            else{
                $('.ajax-u-em.alert.alert-danger.col-sm-8.col-sm-offset-2, .alert.alert-success.col-sm-8.col-sm-offset-2').remove();
                $('.app-u-form').attr('kv_submit', 'false')
                $('.app-u-form').submit();
            }
        },
        error: function(){
            alert('Something went wrong!');
        }
    })
});

$(document).on('change', '[name="files[]"]', function() {
    var file = $(this).val().split('\\');
    file = file[file.length - 1];
    $(this).parent().siblings('.file-u-txt').text(file);
});

$('.get_user_label').on('change', function() {
    var user_id = $(this).val();
    $('[name="id"]').val(user_id);
    $.ajax({
        url: localStorage.getItem('site_url')+'Admin/App/AppCon/get_user_label',
        type: 'POST',
        dataType: 'Json',
        data: {user_id: user_id},
        success: function(res){
            $('.kv-row.remove-row').trigger('click');
            $('.p-r-wrap .row:last .form-control').val('').trigger('change')
            data = res.data; 
            total_records = data.length;
            if (total_records > 0) {
                $('input[name="username"]').val(data[0].username);
                $('input[name="password"]').val(data[0].enc_pass);
                $('input[name="first_name"]').val(data[0].name.split(' ')[0]);
                $('input[name="last_name"]').val(data[0].name.split(' ')[1]);
                $('input[name="email"]').val(data[0].email);
                $('input[name="reference_number"]').val(data[0].reference_number);
            }
            let prevImg = [];
            $.each(data, function(index, val) {
                $('.p-r-wrap .row:last [name="labels[]"]').val(val.label_id).trigger('change');
                $('.p-r-wrap .row:last [name="hidden[files][]"]').val(val.file_name);
                if (val.file_name) 
                    $('.p-r-wrap .row:last .file-u-txt').html('<a href="'+localStorage.getItem('site_url')+'assets/images/'+user_id+'/'+val.file_name+'" download>'+val.file_name+'</a>');
                else
                    $('.p-r-wrap .row:last .file-u-txt').html('');
                // $('[name="copy_id"]').val(user_id);
                prevImg.push(val.file_name);
                if (index+1 == total_records) return;
                $('.kv-row.add-row').trigger('click');
            });
            $('[name="prev_images"]').val(prevImg);
        },
        error: function(){
            alert('Something went wrong!');
        }
    })
});

var appUser = $('.app-users-f').val();
show_copy_button(appUser);

$('.app-users-f').change(function() {
    show_copy_button($(this).val());
});

function show_copy_button(appUser){
    if (appUser == 1) {
        $('.row.exit-users').hide();
        $('.copyUser').show();
        $('.form-lbl').text('Create User');
        $('form.app-u-form').attr('action', localStorage.getItem('site_url')+'app/create-edit-user');
        $('form.app-u-form [name="username"]').removeAttr('readonly');
        $('form.app-u-form [name="username"], form.app-u-form [name="password"], form.app-u-form [name="labels[]"], form.app-u-form  .get_user_label ').val('').trigger('change');
        $('.p-r-wrap .row:last .file-u-txt').text('');
        $('form.app-u-form').removeClass('update');
        $('.app-u-form [type="submit"]').val('Submit');
    }
    else{
        $('.row.exit-users').show();
        $('.copyUser').hide();
        $('.form-lbl').text('Edit User');
        $('form.app-u-form').attr('action', localStorage.getItem('site_url')+'app/user/update');
        $('form.app-u-form [name="username"]').attr('readonly', 'readonly');
        $('.get_user_label').select2();
        $('.p-r-wrap .row:last .file-u-txt').text('');
        $('form.app-u-form').addClass('update');
        $('.get_user_label ').trigger('change');
        $('.app-u-form [type="submit"]').val('Update');
    }
    $('.app-u-l').addClass('c-select2').select2();   
}
$('.copyUser').on('click', function() {
    $('.exit-users').toggle();
    $('.get_user_label').select2();
});

$(document).on('change keyup', '.app-u-f', function(){
    $(this).siblings('input[type="hidden"]').val($(this).val())
})
$(document).bind("ajaxSend", function(){
    $("#ajaxLoader").show();
}).bind("ajaxComplete", function(){
    $("#ajaxLoader").hide();
});